function solve(code, businessLine, isActive) {
    const validCoupons = [];
    const businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"];

    for (let i = 0; i < code.length; i++) {
        if (code[i] && isActive[i]) {
            const business = businessLine[i];
            if (businessOrder.includes(business)) {
                let isValidCode = true;
                for (let j = 0; j < code[i].length; j++) {
                    const char = code[i][j];
                    if (!char.match(/[a-zA-Z0-9_]/)) {
                        isValidCode = false;
                        break;
                    }
                }
                if (isValidCode) {
                    validCoupons.push([business, code[i]]);
                }
            }
        }
    }

    validCoupons.sort((a, b) => {
        const indexA = businessOrder.indexOf(a[0]);
        const indexB = businessOrder.indexOf(b[0]);
        if (indexA !== indexB) return indexA - indexB;
        return a[1].localeCompare(b[1]);
    });

    return validCoupons.map(item => item[1]);
}
